@@ -0,0 +1,45 @@
+namespace Microsoft.Integration.Shopify;
+
+using Microsoft.Sales.Document;
+using Microsoft.Utilities;
+
+/// <summary>
+/// Codeunit Shpfy Copy Document Mgt. (ID 30366).
+/// Handles clearing Shopify fields when copying sales documents.
+/// </summary>
+codeunit 30366 "Shpfy Copy Document Mgt."
+{
+    Access = Internal;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", OnAfterCopySalesDocument, '', true, false)]
+    local procedure ClearShopifyFieldsOnAfterCopySalesDocument(FromDocumentType: Option; FromDocumentNo: Code[20]; var ToSalesHeader: Record "Sales Header"; FromDocOccurenceNo: Integer; FromDocVersionNo: Integer; IncludeHeader: Boolean; RecalculateLines: Boolean; MoveNegLines: Boolean)
+    begin
+        if ToSalesHeader.IsTemporary() then
+            exit;
+
+        ClearShopifyFields(ToSalesHeader);
+    end;
+
+    local procedure ClearShopifyFields(var SalesHeader: Record "Sales Header")
+    var
+        IsModified: Boolean;
+    begin
+        if SalesHeader."Shpfy Order Id" <> 0 then begin
+            SalesHeader."Shpfy Order Id" := 0;
+            IsModified := true;
+        end;
+
+        if SalesHeader."Shpfy Order No." <> '' then begin
+            SalesHeader."Shpfy Order No." := '';
+            IsModified := true;
+        end;
+
+        if SalesHeader."Shpfy Refund Id" <> 0 then begin
+            SalesHeader."Shpfy Refund Id" := 0;
+            IsModified := true;
+        end;
+
+        if IsModified then
+            SalesHeader.Modify();
+    end;
+}
